def table(rows,widths,head=True):
 data=[[P(str(x),'WhiteX' if head and i==0 else ('CellBX' if j==0 else 'CellX')) for j,x in enumerate(r)] for i,r in enumerate(rows)]
 t=Table(data,colWidths=widths,repeatRows=1 if head else 0,hAlign='LEFT')
 cmd=[('VALIGN',(0,0),(-1,-1),'TOP'),('GRID',(0,0),(-1,-1),.35,LINE),('LEFTPADDING',(0,0),(-1,-1),5),('RIGHTPADDING',(0,0),(-1,-1),5),('TOPPADDING',(0,0),(-1,-1),5),('BOTTOMPADDING',(0,0),(-1,-1),5)]
 if head: cmd += [('BACKGROUND',(0,0),(-1,0),NAVY)]
 for i in range(1 if head else 0,len(rows)):
  if i%2==0: cmd.append(('BACKGROUND',(0,i),(-1,i),PAPER))
 t.setStyle(TableStyle(cmd)); return t

